import { SegmentedControl } from '@mantine/core'
import { LayoutGrid, List, Map, Table2 } from 'lucide-react'

export type ViewMode = 'card' | 'list' | 'table' | 'map'

interface ViewToggleProps {
  value: ViewMode
  onChange: (mode: ViewMode) => void
}

const VIEW_OPTIONS = [
  { value: 'card', label: <LayoutGrid size={16} aria-hidden /> },
  { value: 'list', label: <List size={16} aria-hidden /> },
  { value: 'table', label: <Table2 size={16} aria-hidden /> },
  { value: 'map', label: <Map size={16} aria-hidden /> },
]

export function ViewToggle({ value, onChange }: ViewToggleProps) {
  return (
    <SegmentedControl
      size="xs"
      value={value}
      onChange={(v) => onChange(v as ViewMode)}
      data={VIEW_OPTIONS}
      aria-label="View mode"
    />
  )
}

