import type { Page } from '@playwright/test'
import type { DemoMode } from './types'

/**
 * Injects or updates the demo overlay panel on the page.
 * Must be called before each step since navigations destroy injected DOM.
 */
export async function showOverlay(
  page: Page,
  opts: {
    stepIndex: number
    totalSteps: number
    title: string
    description: string
    mode: DemoMode
    pauseMs: number
  },
) {
  await page.evaluate(
    ({ stepIndex, totalSteps, title, description, mode, pauseMs }) => {
      // Remove existing overlay if present
      document.getElementById('demo-overlay')?.remove()

      const panel = document.createElement('div')
      panel.id = 'demo-overlay'
      Object.assign(panel.style, {
        position: 'fixed',
        bottom: '24px',
        right: '24px',
        width: '340px',
        backgroundColor: 'rgba(14, 31, 64, 0.95)',
        color: '#fff',
        borderRadius: '12px',
        padding: '20px',
        fontFamily: 'system-ui, -apple-system, sans-serif',
        zIndex: '99999',
        boxShadow: '0 8px 32px rgba(0,0,0,0.3)',
        backdropFilter: 'blur(8px)',
      })

      const progress = ((stepIndex + 1) / totalSteps) * 100

      panel.innerHTML = `
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
          <span style="font-size:12px;opacity:0.7;text-transform:uppercase;letter-spacing:1px">
            Step ${stepIndex + 1} of ${totalSteps}
          </span>
          <span style="font-size:12px;opacity:0.7">${Math.round(progress)}%</span>
        </div>
        <div style="height:3px;background:rgba(255,255,255,0.15);border-radius:2px;margin-bottom:16px">
          <div style="height:100%;width:${progress}%;background:#c9a227;border-radius:2px;transition:width 0.3s"></div>
        </div>
        <div style="font-size:16px;font-weight:600;margin-bottom:6px">${title}</div>
        <div style="font-size:13px;opacity:0.8;line-height:1.5;margin-bottom:${mode === 'manual' ? '16px' : '0'}">${description}</div>
        ${
          mode === 'manual'
            ? `<button id="demo-advance-btn" style="
                width:100%;
                padding:10px;
                background:#c9a227;
                color:#0e1f40;
                border:none;
                border-radius:8px;
                font-size:14px;
                font-weight:600;
                cursor:pointer;
                transition:opacity 0.15s;
              " onmouseover="this.style.opacity='0.85'" onmouseout="this.style.opacity='1'">
                Next Step ›
              </button>`
            : `<div id="demo-countdown-bar" style="height:3px;background:rgba(255,255,255,0.15);border-radius:2px;margin-top:12px">
                <div id="demo-countdown-fill" style="height:100%;width:100%;background:#c9a227;border-radius:2px;transition:width ${pauseMs}ms linear"></div>
              </div>`
        }
      `

      document.body.appendChild(panel)

      // Set up advance mechanism
      if (mode === 'manual') {
        ;(window as Record<string, unknown>).__demoAdvance = false
        document.getElementById('demo-advance-btn')?.addEventListener('click', () => {
          ;(window as Record<string, unknown>).__demoAdvance = true
        })
      }
    },
    opts,
  )
}

/**
 * Wait for the observer to advance — either by timeout (auto) or button click (manual).
 */
export async function waitForAdvance(page: Page, mode: DemoMode, pauseMs: number) {
  if (mode === 'manual') {
    await page.waitForFunction(() => (window as Record<string, unknown>).__demoAdvance === true, {
      timeout: 0,
    })
  } else {
    // Start the countdown animation
    await page.evaluate(() => {
      const fill = document.getElementById('demo-countdown-fill')
      if (fill) fill.style.width = '0%'
    })
    await page.waitForTimeout(pauseMs)
  }
}

/**
 * Playwright global setup — checks that the dev server is reachable before
 * running any e2e tests. If localhost:8080 is not responding, all tests are
 * skipped with a clear message instead of timing out or failing noisily.
 *
 * Start the dev server manually (`pnpm dev` or `make dev`) before running
 * e2e tests.
 */
async function globalSetup() {
  const baseURL = 'http://localhost:8080'

  try {
    const res = await fetch(baseURL, { signal: AbortSignal.timeout(3_000) })
    if (!res.ok) {
      throw new Error(`Dev server responded with status ${res.status}`)
    }
  } catch {
    console.log(
      `\n⏭  Skipping e2e tests — dev server not available at ${baseURL}.\n` +
        `   Start it with: pnpm dev  (or make dev)\n`,
    )
    process.exit(0)
  }
}

export default globalSetup

