  2→import { steps } from './steps'
  3→import { showOverlay, waitForAdvance } from './overlay'
  4→import type { DemoOptions } from './types'
  5→
  6→const BASE_URL = 'http://localhost:8080'
  7→
  8→async function checkServer(
  9→  url: string,
 10→  label: string,
 11→  init?: RequestInit,
 12→): Promise<{ ok: boolean; detail: string }> {
 13→  try {
 14→    const res = await fetch(url, { signal: AbortSignal.timeout(5000), ...init })
 15→    if (!res.ok) {
 16→      return { ok: false, detail: `${label} responded with HTTP ${res.status}` }
 17→    }
 18→    return { ok: true, detail: '' }
 19→  } catch (err) {
 20→    const msg = err instanceof Error ? err.message : String(err)
 21→    return { ok: false, detail: `${label} at ${url} is not reachable: ${msg}` }
 22→  }
 23→}
 24→
 25→async function preflight(): Promise<void> {
 26→  const web = await checkServer(BASE_URL, 'Web dev server')
 27→  if (!web.ok) {
 28→    console.error('\n--- Demo preflight failed ---\n')
 29→    console.error(`  - ${web.detail}`)
 30→    console.error('\nStart the dev environment first:  make dev\n')
 31→    process.exit(1)
 32→  }
 33→
 34→  // Check the API through the Vite proxy with a minimal GraphQL introspection query
 35→  const api = await checkServer(`${BASE_URL}/graphql`, 'API server (via proxy)', {
 36→    method: 'POST',
 37→    headers: { 'Content-Type': 'application/json' },
 38→    body: JSON.stringify({ query: '{__typename}' }),
 39→  })
 40→  if (!api.ok) {
 41→    console.warn(`\n⚠ ${api.detail}`)
 42→    console.warn('  The demo will run but data-dependent steps may fail or show empty results.\n')
 43→  }
 44→}
 45→
 46→function parseArgs(): DemoOptions {
 47→  const args = process.argv.slice(2)
 48→  const opts: DemoOptions = {
 49→    mode: 'auto',
 50→    pauseMs: 3000,
 51→    startStep: 1,
 52→    browser: 'chromium',
 53→    headless: false,
 54→  }
 55→
 56→  for (const arg of args) {
 57→    if (arg === '--manual') {
 58→      opts.mode = 'manual'
 59→    } else if (arg === '--headless') {
 60→      opts.headless = true
 61→    } else if (arg.startsWith('--pause=')) {
 62→      opts.pauseMs = parseInt(arg.split('=')[1], 10)
 63→    } else if (arg.startsWith('--step=')) {
 64→      opts.startStep = parseInt(arg.split('=')[1], 10)
 65→    } else if (arg.startsWith('--browser=')) {
 66→      const b = arg.split('=')[1] as DemoOptions['browser']
 67→      if (['chromium', 'firefox', 'webkit'].includes(b)) {
 68→        opts.browser = b
 69→      }
 70→    }
 71→  }
 72→
 73→  return opts
 74→}
 75→
 76→async function main() {
 77→  const opts = parseArgs()
 78→
 79→  await preflight()
 80→
 81→  const launchers = { chromium, firefox, webkit }
 82→  const launcher = launchers[opts.browser]
 83→
 84→  if (opts.headless) {
 85→    console.log(`\n🧪 College Power Search Demo (headless smoke test)`)
 86→    console.log(`   Steps: ${steps.length}\n`)
 87→  } else {
 88→    console.log(`\n🎬 College Power Search Demo`)
 89→    console.log(
 90→      `   Mode: ${opts.mode === 'manual' ? 'manual (click to advance)' : `auto (${opts.pauseMs}ms pause)`}`,
 91→    )
 92→    console.log(`   Browser: ${opts.browser}`)
 93→    console.log(`   Steps: ${steps.length}\n`)
 94→  }
 95→
 96→  const browser = await launcher.launch({
 97→    headless: opts.headless,
 98→    slowMo: opts.headless ? 0 : 50,
 99→  })
100→
101→  const context = await browser.newContext({
102→    viewport: { width: 1280, height: 800 },
103→  })
104→  const page = await context.newPage()
105→
106→  const startIndex = Math.max(0, opts.startStep - 1)
107→
108→  try {
109→    for (let i = startIndex; i < steps.length; i++) {
110→      const step = steps[i]
111→      console.log(`  [${i + 1}/${steps.length}] ${step.title}`)
112→
113→      // Run the step action
114→      await step.action(page)
115→
116→      if (!opts.headless) {
117→        // Inject the overlay after the action (in case of navigation)
118→        await showOverlay(page, {
119→          stepIndex: i,
120→          totalSteps: steps.length,
121→          title: step.title,
122→          description: step.description,
123→          mode: opts.mode,
124→          pauseMs: opts.pauseMs,
125→        })
126→
127→        // Wait for advance
128→        if (i < steps.length - 1) {
129→          await waitForAdvance(page, opts.mode, opts.pauseMs)
130→        } else {
131→          // Last step — keep the browser open for the observer
132→          console.log('\n✅ Demo complete. Close the browser to exit.\n')
133→          await page.waitForEvent('close', { timeout: 0 }).catch(() => {})
134→        }
135→      }
136→    }
137→
138→    if (opts.headless) {
139→      console.log('\n✅ All demo steps passed.\n')
140→    }
141→  } catch (err) {
142→    if (
143→      !opts.headless &&
144→      (err as Error).message?.includes('Target page, context or browser has been closed')
145→    ) {
146→      console.log('\n👋 Browser closed. Demo ended.\n')
147→    } else {
148→      throw err
149→    }
150→  } finally {
151→    await browser.close().catch(() => {})
152→  }
153→}
154→
155→main().catch((err) => {
156→  console.error('Demo failed:', err)
157→  process.exit(1)
158→})
